        passCount++;
        console.log(`✓ PASS: "${testCase.id}"`);
    } else {
        failCount++;
        console.log(`✗ FAIL: "${testCase.id}"`);
    }

    console.log(`  Expected: ${testCase.valid ? 'VALID' : 'INVALID'}, Got: ${result ? 'VALID' : 'INVALID'}`);
