    console.log('');
});

console.log(`\n${'='.repeat(50)}`);
console.log(`Summary: ${passCount} passed, ${failCount} failed out of ${testCases.length} tests`);

if (failCount === 0) {
    console.log('✓ All tests passed!');
    process.exit(0);
} else {
    console.log(`✗ ${failCount} test(s) failed!`);
    process.exit(1);
}

